java_code:'class Solution{public ListNode removeNthFromEnd(ListNode head,int n){ListNode dummy=new ListNode(0);dummy.next=head;ListNode slow=dummy,fast=dummy;for(int i=0;i<n;i++)fast=fast.next;while(fast.next!=null){slow=slow.next;fast=fast.next;}slow.next=slow.next.next;return dummy.next;}}',
python_code:'def removeNthFromEnd(head,n):\n    dummy=ListNode(0);dummy.next=head;slow=fast=dummy\n    for _ in range(n): fast=fast.next\n    while fast.next:\n        slow=slow.next;fast=fast.next\n    slow.next=slow.next.next\n    return dummy.next',
