java_code:'class Solution{public ListNode reverseBetween(ListNode head,int left,int right){ListNode dummy=new ListNode(0);dummy.next=head;ListNode prev=dummy;for(int i=0;i<left-1;i++)prev=prev.next;ListNode curr=prev.next;for(int i=0;i<right-left;i++){ListNode nxt=curr.next;curr.next=nxt.next;nxt.next=prev.next;prev.next=nxt;}return dummy.next;}}',
python_code:'def reverseBetween(head,left,right):\n    dummy=ListNode(0);dummy.next=head;prev=dummy\n    for _ in range(left-1): prev=prev.next\n    curr=prev.next\n    for _ in range(right-left):\n        nxt=curr.next;curr.next=nxt.next;nxt.next=prev.next;prev.next=nxt\n    return dummy.next',
cpp_code:'ListNode* reverseBetween(ListNode* head,int left,int right){ListNode dummy(0);dummy.next=head;auto prev=&dummy;for(int i=0;i<left-1;i++)prev=prev->next;auto curr=prev->next;for(int i=0;i<right-left;i++){auto nxt=curr->next;curr->next=nxt->next;nxt->next=prev->next;prev->next=nxt;}return dummy.next;}',
