java_code:'class Solution{public Node copyRandomList(Node head){if(head==null)return null;Map<Node,Node> map=new HashMap<>();Node cur=head;while(cur!=null){map.put(cur,new Node(cur.val));cur=cur.next;}cur=head;while(cur!=null){map.get(cur).next=map.get(cur.next);map.get(cur).random=map.get(cur.random);cur=cur.next;}return map.get(head);}}',
python_code:'def copyRandomList(head):\n    if not head: return None\n    m={}\n    cur=head\n    while cur:\n        m[cur]=Node(cur.val);cur=cur.next\n    cur=head\n    while cur:\n        m[cur].next=m.get(cur.next)\n        m[cur].random=m.get(cur.random)\n        cur=cur.next\n    return m[head]',
